    if (!latStr || !lngStr || latStr.trim() === "" || lngStr.trim() === "") {
      return null;
    }
    var lat = parseFloat(latStr);
    var lng = parseFloat(lngStr);
    if (isNaN(lat) || isNaN(lng)) {
      return null;
    }
